class Solution:
    def distinctPrimeFactors(self, nums):
        MAXV = 1000
        spf = list(range(MAXV + 1))
        i = 2
        while i * i <= MAXV:
            if spf[i] == i:
                for j in range(i * i, MAXV + 1, i):
                    if spf[j] == j:
                        spf[j] = i
            i += 1
        primes = set()
        for num in nums:
            n = num
            while n > 1:
                p = spf[n]
                primes.add(p)
                while n % p == 0:
                    n //= p
        return len(primes)

