class Solution:
    def distinctPrimeFactors(self, nums):
        primes = set()
        for num in nums:
            n = num
            d = 2
            while d * d <= n:
                if n % d == 0:
                    primes.add(d)
                    while n % d == 0:
                        n //= d
                d += 1
            if n > 1:
                primes.add(n)
        return len(primes)

