var distinctPrimeFactors = function(nums) {
    const primes = new Set();
    for (const num of nums) {
        let n = num;
        let d = 2;
        while (d * d <= n) {
            if (n % d === 0) {
                primes.add(d);
                while (n % d === 0) n /= d;
            }
            d++;
        }
        if (n > 1) primes.add(n);
    }
    return primes.size;
};
